+
+    public async Task<List<string>> ListFileSystemPaths(
+        string accountName,
+        string fileSystem,
+        string subscriptionId,
+        string? tenant = null,
+        RetryPolicyOptions? retryPolicy = null)
+    {
+        ValidateRequiredParameters(accountName, fileSystem, subscriptionId);
+
+        var dataLakeServiceClient = await CreateDataLakeServiceClient(accountName, tenant, retryPolicy);
+        var fileSystemClient = dataLakeServiceClient.GetFileSystemClient(fileSystem);
+        var paths = new List<string>();
+
+        try
+        {
+            await foreach (var pathItem in fileSystemClient.GetPathsAsync())
+            {
+                if (pathItem?.Name != null)
+                {
+                    paths.Add(pathItem.Name);
+                }
+            }
+        }
+        catch (Exception ex)
+        {
+            throw new Exception($"Error listing file system paths: {ex.Message}", ex);
+        }
+
+        return paths;
+    }
+
+    private async Task<DataLakeServiceClient> CreateDataLakeServiceClient(
+        string accountName,
+        string? tenant = null,
+        RetryPolicyOptions? retryPolicy = null)
+    {
+        var uri = $"https://{accountName}.dfs.core.windows.net";
+        var options = AddDefaultPolicies(new DataLakeClientOptions());
+
+        if (retryPolicy != null)
+        {
+            options.Retry.Delay = TimeSpan.FromSeconds(retryPolicy.DelaySeconds);
+            options.Retry.MaxDelay = TimeSpan.FromSeconds(retryPolicy.MaxDelaySeconds);
+            options.Retry.MaxRetries = retryPolicy.MaxRetries;
+            options.Retry.Mode = retryPolicy.Mode;
+            options.Retry.NetworkTimeout = TimeSpan.FromSeconds(retryPolicy.NetworkTimeoutSeconds);
+        }
+
+        return new DataLakeServiceClient(new Uri(uri), await GetCredential(tenant), options);
+    }
 }
