    13→using AzureMcp.Services.Azure.Subscription;
    14→using AzureMcp.Services.Azure.Tenant;
    15→using AzureMcp.Services.Caching;
    16→
    17→namespace AzureMcp.Areas.Storage.Services;
    18→
    19→public class StorageService(ISubscriptionService subscriptionService, ITenantService tenantService, ICacheService cacheService) : BaseAzureService(tenantService), IStorageService
    20→{
    21→    private readonly ISubscriptionService _subscriptionService = subscriptionService ?? throw new ArgumentNullException(nameof(subscriptionService));
    22→    private readonly ICacheService _cacheService = cacheService ?? throw new ArgumentNullException(nameof(cacheService));
    23→    private const string CacheGroup = "storage";
    24→    private const string StorageAccountsCacheKey = "accounts";
    25→    private static readonly TimeSpan s_cacheDuration = TimeSpan.FromHours(1);
    26→
    27→    public async Task<List<string>> GetStorageAccounts(string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    28→    {
    29→        ValidateRequiredParameters(subscriptionId);
    30→
    31→        // Create cache key
    32→        var cacheKey = string.IsNullOrEmpty(tenant)
    33→            ? $"{StorageAccountsCacheKey}_{subscriptionId}"
    34→            : $"{StorageAccountsCacheKey}_{subscriptionId}_{tenant}";
    35→
    36→        // Try to get from cache first
    37→        var cachedAccounts = await _cacheService.GetAsync<List<string>>(CacheGroup, cacheKey, s_cacheDuration);
    38→        if (cachedAccounts != null)
    39→        {
    40→            return cachedAccounts;
    41→        }
    42→
    43→        var subscription = await _subscriptionService.GetSubscription(subscriptionId, tenant, retryPolicy);
    44→        var accounts = new List<string>();
    45→        try
    46→        {
    47→            await foreach (var account in subscription.GetStorageAccountsAsync())
    48→            {
    49→                if (account?.Data?.Name != null)
    50→                {
    51→                    accounts.Add(account.Data.Name);
    52→                }
    53→            }
    54→
    55→            // Cache the results
    56→            await _cacheService.SetAsync(CacheGroup, cacheKey, accounts, s_cacheDuration);
    57→        }
    58→        catch (Exception ex)
    59→        {
    60→            throw new Exception($"Error retrieving Storage accounts: {ex.Message}", ex);
    61→        }
    62→
    63→        return accounts;
    64→    }
    65→
    66→    public async Task<List<string>> ListContainers(string accountName, string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    67→    {
    68→        ValidateRequiredParameters(accountName, subscriptionId);
    69→
    70→        var blobServiceClient = await CreateBlobServiceClient(accountName, tenant, retryPolicy);
    71→        var containers = new List<string>();
    72→
    73→        try
    74→        {
    75→            await foreach (var container in blobServiceClient.GetBlobContainersAsync())
    76→            {
    77→                containers.Add(container.Name);
    78→            }
    79→        }
    80→        catch (Exception ex)
    81→        {
    82→            throw new Exception($"Error listing containers: {ex.Message}", ex);
    83→        }
    84→
    85→        return containers;
    86→    }
    87→
    88→    public async Task<List<string>> ListTables(
    89→        string accountName,
    90→        string subscriptionId,
    91→        AuthMethod authMethod = AuthMethod.Credential,
    92→        string? connectionString = null,
    93→        string? tenant = null,
    94→        RetryPolicyOptions? retryPolicy = null)
    95→    {
    96→        ValidateRequiredParameters(accountName, subscriptionId);
    97→
    98→        var tables = new List<string>();
    99→
   100→        try
   101→        {
   102→            // First attempt with requested auth method
   103→            var tableServiceClient = await CreateTableServiceClientWithAuth(
   104→                accountName,
   105→                subscriptionId,
   106→                authMethod,
   107→                connectionString,
   108→                tenant,
   109→                retryPolicy);
   110→
   111→            await foreach (var table in tableServiceClient.QueryAsync())
   112→            {
   113→                tables.Add(table.Name);
   114→            }
   115→            return tables;
   116→        }
   117→        catch (Exception ex) when (
   118→            authMethod == AuthMethod.Credential &&
   119→            ex is RequestFailedException rfEx &&
   120→            (rfEx.Status == 403 || rfEx.Status == 401))
   121→        {
   122→            try
   123→            {
   124→                // If credential auth fails with 403/401, try key auth
   125→                var keyClient = await CreateTableServiceClientWithAuth(
   126→                    accountName, subscriptionId, AuthMethod.Key, connectionString, tenant, retryPolicy);
   127→
   128→                tables.Clear(); // Reset the list for reuse
   129→                await foreach (var table in keyClient.QueryAsync())
   130→                {
   131→                    tables.Add(table.Name);
   132→                }
   133→                return tables;
   134→            }
   135→            catch (Exception keyEx) when (keyEx is RequestFailedException keyRfEx && keyRfEx.Status == 403)
   136→            {
   137→                // If key auth fails with 403, try connection string
   138→                var connStringClient = await CreateTableServiceClientWithAuth(
   139→                    accountName, subscriptionId, AuthMethod.ConnectionString, connectionString, tenant, retryPolicy);
   140→
   141→                tables.Clear(); // Reset the list for reuse
   142→                await foreach (var table in connStringClient.QueryAsync())
   143→                {
   144→                    tables.Add(table.Name);
   145→                }
   146→                return tables;
   147→            }
   148→            catch (Exception keyEx)
   149→            {
   150→                throw new Exception($"Error listing tables with key auth: {keyEx.Message}", keyEx);
   151→            }
   152→        }
   153→        catch (Exception ex) when (
   154→            authMethod == AuthMethod.Key &&
   155→            ex is RequestFailedException rfEx && rfEx.Status == 403)
   156→        {
   157→            try
   158→            {
   159→                // If key auth fails with 403, try connection string
   160→                var connStringClient = await CreateTableServiceClientWithAuth(
   161→                    accountName, subscriptionId, AuthMethod.ConnectionString, connectionString, tenant, retryPolicy);
   162→
   163→                tables.Clear(); // Reset the list for reuse
   164→                await foreach (var table in connStringClient.QueryAsync())
   165→                {
   166→                    tables.Add(table.Name);
   167→                }
   168→                return tables;
   169→            }
   170→            catch (Exception connStringEx)
   171→            {
   172→                throw new Exception($"Error listing tables with connection string: {connStringEx.Message}", connStringEx);
   173→            }
   174→        }
   175→        catch (Exception ex)
   176→        {
   177→            throw new Exception($"Error listing tables: {ex.Message}", ex);
   178→        }
   179→    }
