using AzureMcp.Areas.Storage.Commands;
using AzureMcp.Areas.Storage.Options;
using AzureMcp.Areas.Storage.Options.DataLake.FileSystem;
using AzureMcp.Areas.Storage.Services;
using AzureMcp.Commands.Storage;
using AzureMcp.Services.Telemetry;
using Microsoft.Extensions.Logging;

namespace AzureMcp.Areas.Storage.Commands.DataLake.FileSystem;

public sealed class FileSystemListPathsCommand(ILogger<FileSystemListPathsCommand> logger) : BaseStorageCommand<FileSystemListPathsOptions>()
{
    private const string CommandTitle = "List DataLake File System Paths";
    private readonly ILogger<FileSystemListPathsCommand> _logger = logger;
    private readonly Option<string> _fileSystemOption = StorageOptionDefinitions.FileSystem;

    public override string Name => "list-paths";

    public override string Description =>
        $"""
        List all paths in a Data Lake file system. This command retrieves and displays all paths (files and directories)
        available in the specified file system. Results include path names and are returned as a JSON array.
        Requires {StorageOptionDefinitions.AccountName} and {StorageOptionDefinitions.FileSystemName}.
        """;

    public override string Title => CommandTitle;

    protected override void RegisterOptions(Command command)
    {
        base.RegisterOptions(command);
        command.AddOption(_fileSystemOption);
    }

    protected override FileSystemListPathsOptions BindOptions(ParseResult parseResult)
    {
        var options = base.BindOptions(parseResult);
        options.FileSystem = parseResult.GetValueForOption(_fileSystemOption);
        return options;
    }

    [McpServerTool(Destructive = false, ReadOnly = true, Title = CommandTitle)]
    public override async Task<CommandResponse> ExecuteAsync(CommandContext context, ParseResult parseResult)
    {
        var options = BindOptions(parseResult);

        try
        {
            if (!Validate(parseResult.CommandResult, context.Response).IsValid)
            {
                return context.Response;
            }

            context.Activity?.WithSubscriptionTag(options);

            var storageService = context.GetService<IStorageService>();
            var paths = await storageService.ListFileSystemPaths(
                options.Account!,
                options.FileSystem!,
                options.Subscription!,
                options.Tenant,
                options.RetryPolicy);

            context.Response.Results = paths?.Count > 0
                ? ResponseResult.Create(
                    new FileSystemListPathsCommandResult(paths),
                    StorageJsonContext.Default.FileSystemListPathsCommandResult)
                : null;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error listing file system paths. Account: {Account}, FileSystem: {FileSystem}.",
                options.Account, options.FileSystem);
            HandleException(context, ex);
        }

        return context.Response;
    }

    internal record FileSystemListPathsCommandResult(List<string> Paths);
}

